@RestController
@RequestMapping("/saml")
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/login")
    public ResponseEntity<Void> login(@RequestParam(value = "relayState", required = false) String relayState) throws Exception {
        String redirectUrl = samlService.buildAuthnRequestRedirectUrl(relayState);
        HttpHeaders headers = new HttpHeaders();
        headers.setLocation(java.net.URI.create(redirectUrl));
        return new ResponseEntity<>(headers, HttpStatus.FOUND);
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<Map<String, Object>> acs(@RequestParam("SAMLResponse") String samlResponse,
                                                   @RequestParam(value = "RelayState", required = false) String relayState) throws Exception {
        Map<String, Object> result = samlService.parseAndValidateResponse(samlResponse);
        if (relayState != null) {
            result.put("relayState", relayState);
        }
        return ResponseEntity.ok(result);
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public ResponseEntity<String> metadata() throws Exception {
        return ResponseEntity.ok(samlService.buildMetadata());
    }

    @PostMapping("/logout")
    public ResponseEntity<Map<String, String>> logout(HttpServletRequest request) {
        Map<String, String> response = new HashMap<>();
        response.put("status", "logged_out");
        return ResponseEntity.ok(response);
    }
}